head.script:
// 전역 변수
scwin.memJson = $c.data.getMemInfo();
scwin.loginAcctDeptCd = scwin.memJson.acctDeptCd;
scwin.loginAcctDeptNm = scwin.memJson.acctDeptNm;
scwin.checkUser = false;

scwin.planYr;
scwin.acctDeptCd = "";
scwin.ver = "";
scwin.clsCd = "";

scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;
scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd;
scwin.vUserHomeClsCd = scwin.memJson.userHomeClsCd;
scwin.isSubCompany = false;
scwin.privAdmin = scwin.memJson.privAdmin;
scwin.txtCoClsCd = "";
scwin.isStart = false;

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    $c.sbm.execute(sbm_cd);
};

/**
 * UDC값
 */
scwin.onUdcCompleted = function() {
    $c.gus.cfTurnCreateFlag(true);
    scwin.f_FieldClear();
    scwin.f_GetMgntAcctCd();
    $c.gus.cfEnableObjects([btn_addRow, btn_deleteRow, btn_cancelRow]);
    scwin.f_SetLoginDefault();
    scwin.f_setCompanyInfo();
};

//-------------------------------------------------------------------------
// 로그인 기본값 설정
//-------------------------------------------------------------------------
scwin.f_SetLoginDefault = function() {
    $c.gus.cfSetValue(ed_srchAcctDeptCd,scwin.loginAcctDeptCd);
    $c.gus.cfSetHiddenValue(ed_srchAcctDeptCd,scwin.loginAcctDeptCd);
    $c.gus.cfSetValue(ed_srchAcctDeptNm,scwin.loginAcctDeptNm);
    ed_srchInvestPlanClsCd.focus();
};

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_search,[ica_srchPlanYr, lc_version, ed_coCd, ed_coNm]);
    scwin.f_SetSrchDefault();
};

//-------------------------------------------------------------------------
// 조회 기본값 설정
//-------------------------------------------------------------------------
scwin.f_SetSrchDefault = function() {
    ica_srchPlanYr.setValue($c.date.getServerDateTime("yyyy"));
    scwin.f_GetVersion();
    ica_srchPlanYr.focus();
};

//-------------------------------------------------------------------------
// 조회 : 데이터를 조회한다.
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    if (ds_work.getRowCount() > 0 && ds_work.getModifiedIndex().length > 0) {
        if (await $c.win.confirm(MSG_CM_CRM_005) == false)
            return;
    }

    let ret = await $c.gus.cfValidate([tbl_search]);
    if (!ret) {
        return false;
    }

    if (!scwin.f_CheckHidVal([ed_srchAcctDeptCd])) return false;  //코드 유효성 검증

    scwin.f_SetGridFormat();

    $c.sbm.execute(sbm_search);
};

//-------------------------------------------------------------------------
// 저장 :
//-------------------------------------------------------------------------
scwin.f_Save = async function() {
    if (scwin.clsCd == "1" && ds_work.getModifiedIndex().length==0) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_001, ["자료"]));
    } else {
        if (!await scwin.f_Validation()) return false;

        if(await $c.win.confirm(MSG_CM_CRM_001)){
            scwin.f_CheckDeleted();
            sbm_master.action = "/ac.co.bizplan.SaveInvestmentPlanCMD.do";
            $c.sbm.execute(sbm_master); 
        }
    }
};

//-------------------------------------------------------------------------
// 확정 :
//-------------------------------------------------------------------------
scwin.f_Confirm = async function() {
    if (scwin.clsCd == "2" && ds_work.getModifiedIndex().length==0) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_001, ["자료"]));
    } else {
        if (!await scwin.f_Validation()) return false;

        if(await $c.win.confirm(MSG_CM_CRM_001)){
            scwin.f_CheckDeleted();
            sbm_master.action = "/ac.co.bizplan.ConfirmInvestmentPlanCMD.do";
            $c.sbm.execute(sbm_master); 
        }
    }
};

//-------------------------------------------------------------------------
// Validation.
//-------------------------------------------------------------------------
scwin.f_Validation = async function() {
    let ret = await $c.gus.cfValidate([gr_master]);
    if (!ret) {
        return false;
    }

    let presumeYm = scwin.f_GetPresumeYm();
    let colid = "planYm";

    for (let i = 0; i < ds_work.getRowCount(); i++) {
        if (ds_work.getRowStatus(i) == "C" || ds_work.getRowStatus(i) == "U") {
            planYm = ds_work.getCellData(i, colid);
            if (planYm < presumeYm) {
                await $c.win.alert("년월[" + planYm + "]이 추정년월[" + presumeYm + "] 이전입니다.");
                scwin.f_SetColumn(gr_master, i, colid);
                return false;
            }

            if(planYm.substring(0,4).length < 4){
                await $c.win.alert("년도를 잘못 입력하셨습니다.");
                scwin.f_SetColumn(gr_master, i, colid);
                return false;
            }


            if(planYm.substring(4,6) > 12 || planYm.substring(4,6)< 01){
                await $c.win.alert("년월을 잘못 입력하셨습니다.");
                scwin.f_SetColumn(gr_master, i, colid);
                return false;
            }
        }
    }
    return true;
};

//-------------------------------------------------------------------------
// Grid 컬럼에 포커스를 설정.
//-------------------------------------------------------------------------
scwin.f_SetColumn = function(objGrid, row, colid) {
    objGrid.setFocusedCell(row, colid,true);
};

//-------------------------------------------------------------------------
// 행 추가
//-------------------------------------------------------------------------
scwin.f_Add = async function() {
    let ret = await $c.gus.cfValidate([gr_master]);
    if (!ret) {
        return false;
    }

    let newRow = ds_work.insertRow();
    gr_master.setFocusedCell(newRow, 0);
    scwin.ver = lc_version.getValue();
    scwin.planYr = ica_srchPlanYr.getValue();
    scwin.acctDeptCd = ed_srchAcctDeptCd.getValue();

    if(ds_work.getRowStatus(newRow)=="C"){
        gr_master.setCellReadOnly(newRow, "investPlanClsCd", false);
        gr_master.setCellReadOnly(newRow, "planYm", false);
        gr_master.setCellReadOnly(newRow, "investPlanSeq", false);
    }

    ds_work.setCellData(newRow, "planYr", scwin.planYr);
    ds_work.setCellData(newRow, "ver", scwin.ver);
    ds_work.setCellData(newRow, "acctDeptCd", scwin.acctDeptCd);
    ds_work.setCellData(newRow, "qty", 0);
    ds_work.setCellData(newRow, "amt", 0);
    ds_work.setCellData(newRow, "priority", 0);
};

//-------------------------------------------------------------------------
// 엑셀 Download
//-------------------------------------------------------------------------
scwin.f_Export = async function() {
    if (ds_work.getRowCount() == 0) {
        await $c.win.alert(MSG_CM_WRN_002);
        return;
    }

    let fileName = '투자계획_' + scwin.planYr + "_" + ed_srchAcctDeptNm.getValue() + "_ver_" + lc_version.getValue() +
        "_" + lc_clsCd.getItemArray()[lc_clsCd.getSelectedIndex()].orgLabel;

    $c.data.downloadGridViewExcel(gr_master, { fileName: fileName + ".xlsx", sheetName: fileName, useFooter: "false" });
};

/**
 * 엑셀 파일 업로드
 */
scwin.f_excelUpload = async function () {
    if (scwin.f_GetUpdateAuth() == false) {
        await $c.win.alert("권한이 없습니다.");
        return;
    }

    if ( await $c.gus.cfCheckCreateFlag() == true) {
        await $c.win.alert($c.data.getMessage(MSG_CM_WRN_008,["자료"]));
        return;
    }

    let ret = $c.gus.cfValidate([tbl_search])

    if (!ret) {
        return;
    }

    if(excelUdc.getUpExt() == "1") {
        let options = {
            "fileName": "gridDataUpload.xlsx",
            "status": "C",
            "header":1,
            "type": "1",
            "startRowIndex":0,
            "footerExist":0,
        };

        ds_excel.removeAll();
        await $c.data.uploadGridViewCSV(gr_excel, options);
    } else {
        let options = {
            "fileName": "gridDataUpload.xlsx",
            "status": "C",
            "headerExist":1,
            "useMaxByteLength": ",",
            "type": "1",
            "startRowIndex":0,
            "footerExist":0,
        };
        ds_excel.removeAll();
        await $c.data.uploadGridViewExcel(gr_excel, options);
    }
};

//-------------------------------------------------------------------------
// 엑셀 Upload
//-------------------------------------------------------------------------
scwin.f_Import = async function(){
    if (ds_excel.getRowCount() == 0) {
        $c.gus.cfProgressWinClose();
        await $c.win.alert(MSG_CM_ERR_003);
        return;
    }

    if (await scwin.f_AddRowUploaded()) {
        $c.gus.cfProgressWinClose();
        await $c.win.alert("업로드작업이 완료되었습니다.");
    }
}

//-------------------------------------------------------------------------
// 업로드 자료 추가
//-------------------------------------------------------------------------
scwin.f_AddRowUploaded = async function(){
    let check = await scwin.f_CheckUploadData();
    if (check == false) return false;

    if (ds_excel.getRowCount() > 0) {
        ds_work.removeAll();
        for (i=0; i < ds_excel.getRowCount(); i++) {
            let investPlanClsNm = scwin.f_GetInvestPlanClsNm(ds_excel.getCellData(i,"investPlanClsCd").trim());
            if ($c.gus.cfIsNull(investPlanClsNm)) {
                $c.gus.cfProgressWinClose();
                await $c.win.alert((i+1) + "번째 자료의 투자계획 구분코드는 존재하지 않거나 유효하지 않습니다.");
                return false;
            }

            let row = ds_work.insertRow();

            ds_work.setCellData(row, "ver",lc_version.getValue());
            ds_work.setCellData(row, "planYr", ica_srchPlanYr.getValue());
            ds_work.setCellData(row, "acctDeptCd", ed_srchAcctDeptCd.getValue());
            ds_work.setCellData(row, "investPlanClsCd",ds_excel.getCellData(i, "investPlanClsCd").trim());
            ds_work.setCellData(row, "investPlanClsNm",investPlanClsNm);
            ds_work.setCellData(row, "planYm", ds_excel.getCellData(i, "planYm").replace(/\//g, ""));
            ds_work.setCellData(row, "investPlanSeq",$c.gus.cfIsNull(ds_excel.getCellData(i,"investPlanSeq")) ? "0" : ds_excel.getCellData(i,"investPlanSeq"));
            ds_work.setCellData(row, "summary",ds_excel.getCellData(i, "summary"));
            ds_work.setCellData(row, "qty",ds_excel.getCellData(i, "qty"));
            ds_work.setCellData(row, "amt",ds_excel.getCellData(i, "amt"));
            ds_work.setCellData(row, "priority",ds_excel.getCellData(i, "priority"));
        }
    }
    totalRows.setValue(ds_work.getRowCount());
    return true;
}

//-------------------------------------------------------------------------
// 업로드된 데이터 체크
//-------------------------------------------------------------------------
scwin.f_CheckUploadData = async function(){
    for (i=0; i < ds_work.getRowCount(); i++) {
        if ($c.gus.cfIsNull(ds_work.getCellData(i,"investPlanClsCd"))) {
            $c.gus.cfProgressWinClose();
            await $c.win.alert(MSG_CM_ERR_053, [i + "번째 자료의 계정코드"]) ;
            return false;
        }
        if ($c.gus.cfIsNull(ds_work.getCellData(i,"planYm"))) {
            $c.gus.cfProgressWinClose();
            await $c.win.alert(MSG_CM_ERR_053, [i + "번째 자료의 년월"]) ;
            return false;
        }
    }
    return true;
}

//-------------------------------------------------------------------------
// 버전정보를 구한다.
//-------------------------------------------------------------------------
scwin.f_GetVersion = function() {
    const params = {
        sysCd: "CommonEBC",
        queryId: "retrieveVersionInfo",
        param1: ica_srchPlanYr.getValue().trim() + "00"
    };

    dma_version.setJSON(params);
    $c.sbm.execute(sbm_version);
};

//-------------------------------------------------------------------------
// 최종 Ver을 설정
//-------------------------------------------------------------------------
scwin.f_SetFinalVer = function () {
    if (ds_version.getRowCount() < 1) return;

    let index = 0;

    for (let i = 0; i < ds_version.getRowCount(); i++) {
        if (ds_version.getCellData(i, "col3") == DGlobalValue.TRUE) {
            index = i;
            break;
        }
    }

    lc_version.setSelectedIndex(index);
}

//-------------------------------------------------------------------------
// 코드와 Hidden 값이 같은 지 여부를 반환
//-------------------------------------------------------------------------
scwin.f_CheckHidVal = async function(inObj) {
    if (scwin.f_IsArray(inObj)) {
        for (let i = 0; i < inObj.length; i++) {
            if (scwin.f_CheckHidVal(inObj[i]) == false) return false;
        }
    } else {
        let objName = (inObj.options.validExp).split(":")[0];
        if ($c.gus.cfIsNull($c.gus.cfGetValue(inObj))) return true;

        if (await $c.gus.cfGetValue(inObj) != $c.gus.cfGetHiddenValue(inObj)) {
            await $c.win.alert($c.data.getMessage(MSG_CM_ERR_038, ($c.gus.cfIsNull(objName)?"코드":objName)));
            inObj.focus();
            return false;
        }
    }
    return true;
};

//-------------------------------------------------------------------------
// Array 여부를 반환
//-------------------------------------------------------------------------
scwin.f_IsArray = function(inObj) {
    return (inObj instanceof Array);
};

//-------------------------------------------------------------------------
// 부서코드팝업
//-------------------------------------------------------------------------
scwin.f_deptPopUp = async function(pWinCloseTF) {
    let codeObj = ed_srchAcctDeptCd;
    let nameObj = ed_srchAcctDeptNm;

    let param_y = ica_srchPlanYr.getValue().trim() + "0101";
    let param = param_y + ",,,,,,,,," + ed_coCd.getValue();

    let paramArray = {};
    paramArray.pSelectID = "retrieveAcctDeptCdInfo";
    paramArray.pCode = $c.gus.cfGetValue(codeObj);
    paramArray.pWinCloseTF = pWinCloseTF;
    paramArray.pWhere = param + ",,,0,,1";
    paramArray.pW = "410";

    if (paramArray.pWinCloseTF == 'T' && $c.gus.cfCanOpenPopup(codeObj, nameObj) == false) {
        return;
    }

    if ($c.gus.cfIsNull(paramArray.pCode)) paramArray.pCode = "";
    if ($c.gus.cfIsNull(paramArray.pName)) paramArray.pName = "";


    await udc_acctDeptCdInfo.cfCommonPopUp(scwin.udc_acctDeptCdInfo_callBackFunc, paramArray.pCode, paramArray.pName,
    paramArray.pWinCloseTF, paramArray.pDispCnt,
    paramArray.pTitle, paramArray.pWidth,
    paramArray.pHidden, paramArray.pWhere,
    paramArray.pW, paramArray.pH,
    paramArray.pTop, paramArray.pLeft,
    paramArray.pExistTF, paramArray.pAllSearchTF,
    paramArray.pWtitleSearch);
};

scwin.udc_acctDeptCdInfo_callBackFunc = function(ret) {
    $c.gus.cfSetReturnValue(ret,ed_srchAcctDeptCd,ed_srchAcctDeptNm);
};

//-------------------------------------------------------------------------
// 계정코드팝업
//-------------------------------------------------------------------------
scwin.f_investPlanClsPopUp = async function(pWinCloseTF) {
    let codeObj = ed_srchInvestPlanClsCd;
    let nameObj = ed_srchInvestPlanClsNm;

    let paramArray = {};
    paramArray.pSelectID = "retrieveInvestPlanClsInfo";
    paramArray.pCode = $c.gus.cfGetValue(codeObj);
    paramArray.pWinCloseTF = pWinCloseTF;
    //paramArray.pWhere = "1220000,5";

    if (paramArray.pWinCloseTF == 'T' && $c.gus.cfCanOpenPopup(codeObj, nameObj) == false) {
        return;
    }

    await udc_investPlanClsInfo.cfCommonPopUp(scwin.udc_investPlanClsInfo_callBackFunc, paramArray.pCode, paramArray.pName,
        paramArray.pWinCloseTF, paramArray.pDispCnt,
        paramArray.pTitle, paramArray.pWidth,
        paramArray.pHidden, paramArray.pWhere,
        paramArray.pW, paramArray.pH,
        paramArray.pTop, paramArray.pLeft,
        paramArray.pExistTF, paramArray.pAllSearchTF,
        paramArray.pWtitleSearch);
};

scwin.udc_investPlanClsInfo_callBackFunc = function(ret) {
    $c.gus.cfSetReturnValue(ret, ed_srchInvestPlanClsCd, ed_srchInvestPlanClsNm);
};

//-------------------------------------------------------------------------
// 그리드 포맷설정
//-------------------------------------------------------------------------
scwin.f_SetGridFormat = function() {
    gr_master.setReadOnly(false);

    if (lc_clsCd.getValue() == "1") { //계획
        gr_master.setColumnReadOnly("priority", false);
    } else {                          //확정
        gr_master.setColumnReadOnly("priority", true);
    }
};

//-------------------------------------------------------------------------
// 투자계획 그리드 팝업 호출
//-------------------------------------------------------------------------
scwin.f_investPlanClsGridPopUp = async function(pWinCloseTF, oldData) {
    let codeCol = "investPlanClsCd";
    let nameCol = "investPlanClsNm";
    let row = ds_work.getRowPosition();
    let newData = ds_work.getCellData(row, codeCol);

    if (pWinCloseTF == "T") {
        if ($c.gus.cfIsNull(newData)) {
            ds_work.setCellData(row, nameCol, "");
            return;
        }
        if (newData == oldData) return;
    }

    let paramArray = {};
    paramArray.pSelectID = "retrieveInvestPlanClsInfo";
    paramArray.pCode = newData;
    paramArray.pName = "";
    paramArray.pWinCloseTF = pWinCloseTF;
    //paramArray.pWhere = "1220000,5";
    //paramArray.pW = "410";

    if ($c.gus.cfIsNull(paramArray.pCode)) paramArray.pCode = "";
    if ($c.gus.cfIsNull(paramArray.pName)) paramArray.pName = "";

    await udc_gridInvestPlanClsInfo.cfCommonPopUp(scwin.udc_gridInvestPlanClsInfo_callBackFunc, paramArray.pCode, paramArray.pName,
        paramArray.pWinCloseTF, paramArray.pDispCnt,
        paramArray.pTitle, paramArray.pWidth,
        paramArray.pHidden, paramArray.pWhere,
        paramArray.pW, paramArray.pH,
        paramArray.pTop, paramArray.pLeft,
        paramArray.pExistTF, paramArray.pAllSearchTF,
        paramArray.pWtitleSearch);
};

scwin.udc_gridInvestPlanClsInfo_callBackFunc = async function(rtnList) {
    let row = ds_work.getRowPosition();
    // SET
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ds_work.setCellData(row, "investPlanClsCd", rtnList[0]);
        ds_work.setCellData(row, "investPlanClsNm", rtnList[1]);
    } else {
        ds_work.setCellData(row, "investPlanClsCd", "");
        ds_work.setCellData(row, "investPlanClsNm", "");
    }
};


//-------------------------------------------------------------------------
// 투자계획구분목록을 구한다.
//-------------------------------------------------------------------------
scwin.f_GetMgntAcctCd = function() {
    const params = {
        sysCd: "CommonEBC",
        queryId: "retrieveInvestPlanClsInfo",
        param1: "",
        param2: "",
        param3: "1220000",
        param4: "5"
    };

    dma_investPlanClsCd.setJSON(params);
    $c.sbm.execute(sbm_investPlanClsCd);
};

//-------------------------------------------------------------------------
// 투자계획구분명을 구한다.
//-------------------------------------------------------------------------
scwin.f_GetInvestPlanClsNm = function(investPlanClsCd) {
    let rowIdx = ds_investPlanClsCd.getMatchedIndex("col1", investPlanClsCd);
    if (rowIdx.length == 0) return null;
    return ds_investPlanClsCd.getCellData(rowIdx[0], "col2");
};

//-------------------------------------------------------------------------
// 추정년월을 반환
//-------------------------------------------------------------------------
scwin.f_GetPresumeYm = function() {
    let row = ds_version.getMatchedIndex("col1",lc_version.getValue()).length;
    let target = ds_version.getMatchedIndex("col1",lc_version.getValue());
    if (row < 1) {
        return "";
    }
    else{
        return ds_version.getCellData(target[0],"col5");
    }
}

//-------------------------------------------------------------------------
// 구분에 따른 데이터의 유무 설정
//-------------------------------------------------------------------------
scwin.f_MakeWorkData  = function() {
    if (ds_master.getRowCount() == 0) return;

    ds_work.removeAll();   
    for (i=0; i < ds_master.getRowCount(); i++) {
        if (lc_clsCd.getValue() == "1") {
            if (scwin.f_ExistPlanData(i)) {
                let row = ds_work.insertRow();
                ds_work.setCellData(row, "ver", ds_master.getCellData(i, "ver"));
                ds_work.setCellData(row, "planYr", ds_master.getCellData(i, "planYr"));
                ds_work.setCellData(row, "planYm", ds_master.getCellData(i, "planYm"));
                ds_work.setCellData(row, "acctDeptCd", ds_master.getCellData(i, "acctDeptCd"));
                ds_work.setCellData(row, "acctDeptNm", ds_master.getCellData(i, "acctDeptNm"));
                ds_work.setCellData(row, "investPlanClsCd", ds_master.getCellData(i, "investPlanClsCd"));
                ds_work.setCellData(row, "investPlanClsNm", ds_master.getCellData(i, "investPlanClsNm"));
                ds_work.setCellData(row, "investPlanSeq", ds_master.getCellData(i, "investPlanSeq"));
                ds_work.setCellData(row, "summary", ds_master.getCellData(i, "planSummary"));
                ds_work.setCellData(row, "qty", ds_master.getCellData(i, "planQty"));
                ds_work.setCellData(row, "amt", ds_master.getCellData(i, "planAmt"));
                ds_work.setCellData(row, "priority", ds_master.getCellData(i, "priority"));
                ds_work.setCellData(row, "flag", (scwin.f_ExistConfirmData(i) ? 1 : 0));
            }
        } else {
            if (scwin.f_ExistConfirmData(i)) {
                let row = ds_work.insertRow();
                ds_work.setCellData(row, "ver", ds_master.getCellData(i, "ver"));
                ds_work.setCellData(row, "planYr", ds_master.getCellData(i, "planYr"));
                ds_work.setCellData(row, "planYm", ds_master.getCellData(i, "planYm"));
                ds_work.setCellData(row, "acctDeptCd", ds_master.getCellData(i, "acctDeptCd"));
                ds_work.setCellData(row, "acctDeptNm", ds_master.getCellData(i, "acctDeptNm"));
                ds_work.setCellData(row, "investPlanClsCd", ds_master.getCellData(i, "investPlanClsCd"));
                ds_work.setCellData(row, "investPlanClsNm", ds_master.getCellData(i, "investPlanClsNm"));
                ds_work.setCellData(row, "investPlanSeq", ds_master.getCellData(i, "investPlanSeq"));
                ds_work.setCellData(row, "summary", ds_master.getCellData(i, "dcsnSummary"));
                ds_work.setCellData(row, "qty", ds_master.getCellData(i, "dcsnQty"));
                ds_work.setCellData(row, "amt", ds_master.getCellData(i, "dcsnAmt"));
                ds_work.setCellData(row, "priority", ds_master.getCellData(i, "priority"));
                ds_work.setCellData(row, "flag", (scwin.f_ExistPlanData(i) ? 1 : 0));
            }
        }
    }

    ds_work.modifyAllStatus("R");
    ds_work.reform();
}

//-------------------------------------------------------------------------
// 계획내역이 존재하는 지 여부를 반환한다.
//-------------------------------------------------------------------------
scwin.f_ExistPlanData = function(row) {
    if (row == null) row = ds_master.getRowPosition();
    if (!$c.gus.cfIsNull(ds_master.getCellData(row, "planSummary"))) return true;
    if (ds_master.getCellData(row, "planQty") != 0) return true;
    if (ds_master.getCellData(row, "planAmt") != 0) return true;
    return false;
};

//-------------------------------------------------------------------------
// 확정내역이 존재하는 지 여부를 반환한다.
//-------------------------------------------------------------------------
scwin.f_ExistConfirmData = function(row) {
    if (row == null) row = ds_master.getRowPosition();
    if (!$c.gus.cfIsNull(ds_master.getCellData(row, "dcsnSummary"))) return true;
    if (ds_master.getCellData(row, "dcsnQty") != 0) return true;
    if (ds_master.getCellData(row, "dcsnAmt") != 0) return true;
    return false;
};

//-------------------------------------------------------------------------
// 수정할 수 있는 권한이 있는 지 여부를 반환
//-------------------------------------------------------------------------
scwin.f_GetUpdateAuth = function() {
    let frame = $c.gus.getFrm();

    if (!$c.gus.cfCheckAuthCREATE(frame) && !$c.gus.cfCheckAuthUPDATE(frame))
        return false;

    scwin.clsCd = lc_clsCd.getValue();

    if (scwin.clsCd == "1")
        return $c.gus.cfCheckAuthCREATE(frame);
    else if (scwin.clsCd == "2")
        return $c.gus.cfCheckAuthUPDATE(frame);

    return false;
};

//-------------------------------------------------------------------------
// 행추가/삭제/취소버튼의 Enalbe/Disable 설정
//-------------------------------------------------------------------------
scwin.f_SetRowButton = function() {
    if (scwin.f_GetUpdateAuth()) {
        $c.gus.cfEnableObjects([btn_addRow, btn_deleteRow, btn_cancelRow]);
    } else {
        $c.gus.cfDisableObjects([btn_addRow, btn_deleteRow, btn_cancelRow]);
    }
};

//-------------------------------------------------------------------------
// 삭제된 데이터를 실제 삭제할 지 여부를 체크
//-------------------------------------------------------------------------
scwin.f_CheckDeleted = function() {
    for (let i = 0; i < ds_work.getRowCount(); i++) {
        if (ds_work.getRowStatus(i) == "D") { //삭제
            if (ds_work.getCellData(i, "flag") == "1") {
                $c.data.undoRow(ds_work, "Y");
                ds_work.setCellData(i, "planSummary", "");
                ds_work.setCellData(i, "planQty", 0);
                ds_work.setCellData(i, "planAmt", 0);
            }
        }
    }
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {   
 	 // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
 	if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
	}

    scwin.isStart = true;
	ed_coCd.setValue(scwin.vLoginCoCd);
	scwin.f_PopUpCompanyInfo('T');
}

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function(pWinCloseTF) {
    udc_dongbuGroupCompanyInfo.cfCommonPopUp(scwin.udc_dongbuGroupCompanyInfo_callBackFunc
    									,ed_coCd.getValue(), ""
    									,pWinCloseTF,null,null,null,null
    									,null,null,null,null,null);   
}

scwin.udc_dongbuGroupCompanyInfo_callBackFunc = function(rtnList) {
        // SET
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;

        ed_coCd.setValue(rtnList[0]);   // 코드
        ed_coNm.setValue(rtnList[5]);   // 회사명
        scwin.txtCoClsCd = rtnList[1];  // 회사구분
    } else {
        ed_coNm.setValue("");
        ed_coCd.setValue("");
        scwin.txtCoClsCd = "";
    }

    if(scwin.isStart == true) {
        if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU)  {  	// 자회사 회계 시스템 
		    scwin.isSubCompany = true;
        }else{
            scwin.isSubCompany = false;
        }

        if('T' == scwin.privAdmin  ||  !scwin.isSubCompany   ) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
            $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_company]);    
        }else {
            $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company]);   
        }  
    }
    scwin.isStart = false;
};

scwin.sbm_search_submitdone = async function (e) {
    if(await $c.gus.cfCheckCreateFlag() == true){
        await $c.gus.cfTurnCreateFlag(false);
    }



    scwin.f_MakeWorkData();   //임시데이터셋 생성
    gr_master.setFocusedCell(ds_work.getRowCount()-1, 0);
    totalRows.setValue(ds_work.getRowCount());
    if( ds_master.getRowCount() == 0 ){
        await $c.win.alert(MSG_CM_WRN_002);
        ds_work.removeAll();
    }
};

scwin.sbm_master_submitdone = async function (e) {
    await $c.win.alert(MSG_CM_INF_001);
    ds_work.reform();
    scwin.f_Retrieve();
};

scwin.sbm_version_submitdone = function (e) {
