scwin.gr_master_oncellclick = function (row, columnIndex, colid) {
    if (row < 0) return;
    if (colid == "investPlanClsNm" || colid == "flag" || colid == "priority") return;

    if (ds_master.getRowStatus(row) == "C") {
        gr_master.setColumnReadOnly(colid,false);
    } else {
        if (colid == "investPlanClsCd" || colid == "planYm" || colid == "investPlanSeq"){
            gr_master.setColumnReadOnly(colid,true);
        }else{
            gr_master.setColumnReadOnly(colid,false);
        }
    }
};

scwin.gr_master_ontextimageclick = function (rowIndex, columnIndex) {
    let colId = gr_master.getColumnID(columnIndex);
    if (colId == "investPlanClsCd") {
        scwin.f_investPlanClsGridPopUp('F');
    }
};

scwin.sbm_cd_submitdone = function (e) {
    let coList = ds_cd.getColData("cdDesc");
    let isMatch = coList.includes(scwin.memJson.userId);

    if(isMatch) {
        btn_confirm.setStyle("display", "block");
    } else {
        btn_confirm.setStyle("display", "none");
    }
};

scwin.ds_master_onbeforerowpositionchange = async function (info) {
    if (info.oldRowIndex < 1) return;

    let ret = await $c.gus.cfValidate([gr_master]);
    return ret;
};

scwin.gr_master_onviewchange = function (info) {
    let colId = info.colId;
    switch (colId) {
        case "investPlanClsCd":
            scwin.f_investPlanClsGridPopUp('T',info.oldValue);
            break;
    }
};

scwin.gr_excel_onfilereadend = function (value) {
